public class FactoryBug {
    interface Animal { String sound(); }
    static class Dog implements Animal { public String sound() { return "woof"; } }
    static class Cat implements Animal { public String sound() { return "meow"; } }
    static Animal create(String type) {
        if (type.equals("dog")) return new Dog();
        if (type.equals("cat")) return new Cat();
        return new Dog();   // bug: should throw for unknown type
    }
    public static void main(String[] args) {
        System.out.println(create("fish").sound());  // silently returns Dog!
    }
}
